<?php
namespace Tests\Feature;
use App\Models\Item;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class EquipmentStatsSchemaTest extends TestCase{use RefreshDatabase;public function test_item_bonus_columns_have_expected_unsigned_types_and_zero_defaults(){$integerColumns=['max_health_bonus','attack_bonus','defense_bonus','accuracy_bonus','evasion_bonus'];$decimalColumns=['critical_chance_bonus','attack_speed_bonus'];$this->assertTrue(Schema::hasColumns('items',array_merge($integerColumns,$decimalColumns)));$definitions=collect(DB::select("SHOW COLUMNS FROM items"))->keyBy('Field');foreach($integerColumns as $column){$this->assertSame('0',$definitions[$column]->Default);$this->assertStringContainsString('unsigned',$definitions[$column]->Type);}foreach($decimalColumns as $column){$this->assertSame('0.00',$definitions[$column]->Default);$this->assertSame('decimal(5,2) unsigned',$definitions[$column]->Type);}$this->assertTrue(Schema::hasColumn('hunts','character_stats_snapshot'));}public function test_existing_non_equipment_items_receive_zero_bonuses(){$item=Item::create(['code'=>'zero_bonus_material','name'=>'Material','item_type'=>'material','equipment_type'=>null,'rarity'=>'common','is_stackable'=>true,'max_stack'=>10,'status'=>'active']);foreach(['max_health_bonus','attack_bonus','defense_bonus','accuracy_bonus','evasion_bonus'] as $column)$this->assertSame(0,$item->fresh()->{$column});$this->assertSame('0.00',$item->fresh()->critical_chance_bonus);$this->assertSame('0.00',$item->fresh()->attack_speed_bonus);}}
